#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define ETA 0.3f
#define MOMENTUM 0.3f
#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16

__kernel void bpnn_layerforward_ocl(
    __global float* input_units,
    __global float* hidden_units,
    __global float* input_weights,
    __global float* hidden_partial_sum,
    __local float* local_l1,
    __local float* local_conn,
    const int input_n,
    const int hidden_n)
{
    int tx = get_local_id(0);
    int ty = get_local_id(1);
    int bx = get_group_id(0);
    int by = get_group_id(1);

    int row = bx * BLOCK_SIZE + tx; // index in input dimension (k)
    int col = by * BLOCK_SIZE + ty; // index in hidden dimension (j)

    // Load l1 (input_units) values into local memory, for this block
    if (ty == 0 && row <= input_n) {
        local_l1[tx] = input_units[row];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        int idx_k = bx * BLOCK_SIZE + i;
        int idx_j = by * BLOCK_SIZE + ty;
        if (idx_k <= input_n && idx_j <= hidden_n) {
            // Load conn to local memory
            int conn_idx = idx_k * (hidden_n + 1) + idx_j;
            local_conn[i * BLOCK_SIZE + ty] = input_weights[conn_idx];
        }
        else {
            local_conn[i * BLOCK_SIZE + ty] = 0.0f;
        }
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (row <= input_n && col <= hidden_n) {
        for (int i = 0; i < BLOCK_SIZE; i++) {
            sum += local_conn[i * BLOCK_SIZE + ty] * local_l1[i];
        }
        // Write partial sum for this work-item
        int partial_sum_idx = bx * get_num_groups(1) * BLOCK_SIZE + by * BLOCK_SIZE + ty;
        hidden_partial_sum[partial_sum_idx] = sum;
    }
}

__kernel void bpnn_adjust_weights_ocl(
    __global float* delta,
    const int delta_n,
    __global float* ly,
    const int ly_n,
    __global float* w,
    __global float* oldw)
{
    int k = get_global_id(0); // ly index: 0..ly_n
    int j = get_global_id(1); // delta index: 1..delta_n

    if (j >= 1 && j <= delta_n && k <= ly_n) {
        int idx = k * (delta_n + 1) + j;
        float new_dw = ETA * delta[j] * ly[k] + MOMENTUM * oldw[idx];
        w[idx] += new_dw;
        oldw[idx] = new_dw;
    }
}
